import{c as o,Q as a,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const q=JSON.parse('{"title":"注册表、标签、维度与修饰 / 信号 / 会话层","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/11-注册表-标签维度与修饰信号会话层.md","filePath":"minecraftLearning/11-注册表-标签维度与修饰信号会话层.md","lastUpdated":1781674740000}'),s={name:"minecraftLearning/11-注册表-标签维度与修饰信号会话层.md"};function r(d,t,i,p,u,l){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="注册表、标签、维度与修饰-信号-会话层" tabindex="-1">注册表、标签、维度与修饰 / 信号 / 会话层 <a class="header-anchor" href="#注册表、标签、维度与修饰-信号-会话层" aria-label="Permalink to &quot;注册表、标签、维度与修饰 / 信号 / 会话层&quot;">​</a></h1><p>前面十篇我们把世界&quot;长什么样、怎么跑、怎么存&quot;讲透了:体素、噪声、渲染、tick、存储、方块、实体、流体、物品、生物群系、光照……每讲一类,你脑子里大概都冒过同一个问题——</p><blockquote><p>这些&quot;种类&quot;到底是从哪冒出来的?谁规定了&quot;3 号方块是石头&quot;?为什么我装个 mod 就能凭空多出一种方块、一种维度?</p></blockquote><p>这一篇回答的就是这个&quot;元问题&quot;。它不再讲世界里的某个具体对象,而是讲<strong>把所有对象的&quot;类型&quot;装起来的那个总系统</strong>,以及几类我们前面顺带提过、但没正面展开的&quot;非对象&quot;层:修饰层、运行时信号、交互会话层,最后是兜住一切的维度与存档容器。</p><blockquote><p>一句话先记住:<strong>世界里能存在的每一种东西,都得先在&quot;注册表&quot;里上户口拿到一个 ID;注册表就是 Minecraft 的户口本,也是贯穿&quot;类型—存储—网络—数据包—版本演进&quot;的那根主轴。</strong></p></blockquote><hr><h2 id="一、注册表-registry-一切-类型-的总账" tabindex="-1">一、注册表 Registry:一切&quot;类型&quot;的总账 <a class="header-anchor" href="#一、注册表-registry-一切-类型-的总账" aria-label="Permalink to &quot;一、注册表 Registry:一切&quot;类型&quot;的总账&quot;">​</a></h2><p>回想前几篇反复出现的&quot;类型层 vs 实例层&quot;:<code>Block</code>(石头这一类)是单例,<code>BlockState</code> 下标(世界里那一个)是实例;<code>Item</code> 是类型,<code>ItemStack</code> 是实例;<code>EntityType</code> 是类型,<code>Entity</code> 是实例。</p><p>这些<strong>类型</strong>(每种方块、每种物品、每种实体类型、每种流体、每种生物群系、每种状态效果、每种附魔……)不是散落在代码各处的,而是<strong>全部登记在注册表里</strong>。你前几篇问的&quot;世界里还有哪些类别&quot;,最终答案就是一句:</p><blockquote><p>去翻注册表里有哪些 Registry。每一种 Registry 就是一类东西的名册。</p></blockquote><h3 id="上户口会拿到两套-id" tabindex="-1">上户口会拿到两套 ID <a class="header-anchor" href="#上户口会拿到两套-id" aria-label="Permalink to &quot;上户口会拿到两套 ID&quot;">​</a></h3><p>每个注册项登记后,拿到两个标识:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>命名空间 ID(资源位 ResourceLocation): minecraft:stone</span></span>
<span class="line"><span>数字 ID(运行时分配的整数):           例如 1</span></span></code></pre></div><table tabindex="0"><thead><tr><th>标识</th><th>给谁用</th><th>特点</th></tr></thead><tbody><tr><td>命名空间 ID</td><td>人 / 数据包 / 命令</td><td>稳定、可读;<code>minecraft:</code> 是原版,mod/数据包用自己的前缀</td></tr><tr><td>数字 ID</td><td>机器(网络、存盘)</td><td>紧凑;传 <code>1</code> 远比传 <code>&quot;minecraft:stone&quot;</code> 省</td></tr></tbody></table><p><strong>命名空间是可扩展性的基石。</strong> 因为每个东西都带前缀,你的 mod 注册 <code>mymod:ruby_block</code>、我的数据包注册 <code>atlasandecho:foo</code>,天然不会撞车。这就是 Minecraft 生态能容纳成千上万 mod 而不互相踩踏的根本原因。</p><p><strong>数字 ID 是性能的基石。</strong> 还记得第八篇 chunk 的 section 用&quot;局部调色板 + 紧凑位数组&quot;存方块?调色板里那一条,指向的就是注册表里某个 BlockState 的<strong>全局数字 ID</strong>。网络同步、存盘 palette,传的都是数字而不是字符串。</p><hr><h2 id="二、两个关键机制-冻结与同步" tabindex="-1">二、两个关键机制:冻结与同步 <a class="header-anchor" href="#二、两个关键机制-冻结与同步" aria-label="Permalink to &quot;二、两个关键机制:冻结与同步&quot;">​</a></h2><p>注册表能当&quot;户口本&quot;用,靠两条纪律。</p><h3 id="_1-启动时冻结-freeze" tabindex="-1">1. 启动时冻结(freeze) <a class="header-anchor" href="#_1-启动时冻结-freeze" aria-label="Permalink to &quot;1. 启动时冻结(freeze)&quot;">​</a></h3><p>游戏启动 → 加载所有原版 + mod + 数据包的注册项 → <strong>冻结注册表</strong>。冻结后不能再加新条目。</p><p>为什么必须冻结?因为运行期间&quot;3 号方块是什么&quot;必须<strong>固定不变</strong>——palette 下标、网络协议、存盘里的数字 ID 才有确定含义。如果运行中还能往注册表里塞东西、重排编号,那磁盘上写过的所有 palette 全部失效。</p><h3 id="_2-进服时同步-registry-sync" tabindex="-1">2. 进服时同步(registry sync) <a class="header-anchor" href="#_2-进服时同步-registry-sync" aria-label="Permalink to &quot;2. 进服时同步(registry sync)&quot;">​</a></h3><p>多人游戏有个隐患:<strong>服务端的&quot;1 号方块&quot;和客户端的&quot;1 号方块&quot;必须是同一个东西</strong>,否则你看到的世界整体错位——服务端说&quot;这格是 1&quot;,客户端把 1 解析成别的方块。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>玩家连入</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ 服务端把注册表的 ID 映射打包发给客户端   (registry sync)</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ 客户端按服务端的编号重新对齐自己的注册表</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   └─ 双方对&quot;几号是什么&quot;达成一致 → 世界才能正确显示</span></span></code></pre></div><blockquote><p><strong>踩坑 / 反直觉:</strong> &quot;装了服务端没有的 mod、或版本不匹配就进不去&quot;,本质就是注册表对不上——客户端有些条目服务端没有,ID 映射对不齐,握手直接失败。很多人以为是&quot;版本号检查&quot;,其实更底层的是注册表一致性检查。</p></blockquote><h3 id="_3-静态注册表-vs-动态注册表" tabindex="-1">3. 静态注册表 vs 动态注册表 <a class="header-anchor" href="#_3-静态注册表-vs-动态注册表" aria-label="Permalink to &quot;3. 静态注册表 vs 动态注册表&quot;">​</a></h3><p>不是所有注册表都一样&quot;硬&quot;。</p><table tabindex="0"><thead><tr><th>类型</th><th>谁定义</th><th>例子</th></tr></thead><tbody><tr><td><strong>静态注册表</strong></td><td>代码硬编码,启动注册</td><td>方块、物品、实体类型、流体</td></tr><tr><td><strong>动态注册表</strong></td><td><strong>数据包的 JSON 驱动</strong>,启动从数据包加载</td><td>生物群系、维度类型、世界生成配置、消息类型</td></tr></tbody></table><p>动态注册表同样参与进服同步。这就解释了一个很多人觉得&quot;魔法&quot;的现象:</p><blockquote><p>为什么如今做自定义维度、自定义生物群系<strong>不用写一行 Java、改几个 JSON 就行</strong>?</p></blockquote><p>因为它们是<strong>数据驱动的注册项</strong>。世界生成、维度、生物群系早已从&quot;硬编码&quot;重构成&quot;数据包定义&quot;,启动时被读进动态注册表,和原版条目一视同仁。</p><hr><h2 id="三、标签-tag-给注册项分组" tabindex="-1">三、标签 Tag:给注册项分组 <a class="header-anchor" href="#三、标签-tag-给注册项分组" aria-label="Permalink to &quot;三、标签 Tag:给注册项分组&quot;">​</a></h2><p>注册表解决&quot;有哪些东西&quot;,<strong>标签</strong>解决&quot;哪些东西算一类&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#minecraft:logs    → 所有原木(橡木原木、白桦原木、去皮原木、绯红菌柄…)</span></span>
<span class="line"><span>#minecraft:planks  → 所有木板</span></span>
<span class="line"><span>#minecraft:doors   → 所有门</span></span></code></pre></div><p>标签的三个关键性质:</p><ul><li><strong>被规则引用而非逐个列举</strong>:合成、方块行为、命令选择器、战利品条件,大量写&quot;匹配 <code>#minecraft:logs</code>&quot;而不是把每种原木列一遍。</li><li><strong>数据驱动、可被数据包扩展并合并</strong>:多个数据包可以往同一个标签里各加几条,最终<strong>合并</strong>成一个标签内容,而不是互相覆盖。</li><li><strong>对未来自动生效</strong>:正因为规则写的是标签,&quot;任意原木都能合成木板&quot;这条规则,会对以后版本/mod 新增的任何原木<strong>自动适用</strong>——只要新原木进了 <code>#minecraft:logs</code>。</li></ul><blockquote><p>标签是&quot;开闭原则&quot;在游戏数据层的落地:对扩展开放(往标签加条目),对修改封闭(规则不用改)。</p></blockquote><hr><h2 id="四、注册表如何咬合前面所有篇" tabindex="-1">四、注册表如何咬合前面所有篇 <a class="header-anchor" href="#四、注册表如何咬合前面所有篇" aria-label="Permalink to &quot;四、注册表如何咬合前面所有篇&quot;">​</a></h2><p>把注册表当主轴,前十篇的零散点会被一根线串起来:</p><table tabindex="0"><thead><tr><th>现象(前面某篇)</th><th>背后是注册表</th></tr></thead><tbody><tr><td>section palette 里的下标(03 / 08)</td><td>指向注册表里的 BlockState 全局数字 ID</td></tr><tr><td>chunk NBT 里写 <code>minecraft:chest</code>(08 / 09)</td><td>加载时查注册表,把命名空间 ID 还原成具体类型</td></tr><tr><td>跨版本升级 DataVersion / DataFixerUpper(08)</td><td>本质是处理&quot;注册表条目随版本增删 / 改名&quot;后,旧 ID、旧名怎么迁移到新注册表</td></tr><tr><td>数据包能改游戏(本篇)</td><td>因为内容定义和动态注册表对数据包开放</td></tr><tr><td>进服失败 / mod 不一致(本篇)</td><td>注册表 ID 映射对不齐</td></tr></tbody></table><p>所以注册表不是&quot;又一个系统&quot;,而是<strong>那根贯穿类型层、存储、网络、数据包、版本演进的主轴</strong>。理解了它,前面所有&quot;为什么这里写的是个 ID / 字符串&quot;的疑问都收口了。</p><hr><h2 id="五、修饰层-贴在对象上的-形容词" tabindex="-1">五、修饰层:贴在对象上的&quot;形容词&quot; <a class="header-anchor" href="#五、修饰层-贴在对象上的-形容词" aria-label="Permalink to &quot;五、修饰层:贴在对象上的&quot;形容词&quot;&quot;">​</a></h2><p>注册表登记的是&quot;名词&quot;(类型)。但游戏里还有一整套<strong>修饰系统</strong>——它们不是独立对象,而是&quot;贴&quot;在实体或物品上,改变其行为。</p><table tabindex="0"><thead><tr><th>系统</th><th>贴在谁身上</th><th>作用</th><th>存哪</th></tr></thead><tbody><tr><td><strong>属性 Attribute</strong></td><td>生物实体</td><td>最大生命、移速、攻击力、护甲、击退抗性…</td><td>实体 NBT(带 modifier 列表)</td></tr><tr><td><strong>状态效果 MobEffect</strong>(药水效果)</td><td>生物实体</td><td>速度 / 中毒 / 再生…,<strong>每 tick 结算</strong></td><td>实体 NBT(active_effects)</td></tr><tr><td><strong>附魔 Enchantment</strong></td><td>物品</td><td>锋利、保护、效率…,改物品行为</td><td>物品上</td></tr><tr><td><strong>数据组件 Data Component</strong></td><td>物品</td><td>1.20.5 起物品就是&quot;一组组件&quot;拼成的</td><td>物品组件</td></tr></tbody></table><p>这里单独说一句 <strong>1.20.5 的物品模型重构</strong>:在那之前,物品的额外数据塞在一坨自由格式的 NBT <code>tag</code> 里(附魔、自定义名、耐久……全堆在一起,没有强结构)。1.20.5 之后改成<strong>数据组件(Data Components)</strong>:一个物品 = 一组<strong>有明确类型的组件</strong>(<code>minecraft:enchantments</code>、<code>minecraft:custom_name</code>、<code>minecraft:damage</code>…)。这是从&quot;一坨弱类型 NBT&quot;到&quot;强类型组件集合&quot;的架构升级,本质和&quot;BlockState 用强类型属性而非散 NBT&quot;是同一种思路。</p><blockquote><p><strong>反直觉:</strong> 这些修饰单独拎出来都&quot;不是世界里的东西&quot;,但游戏的大量深度恰恰住在这一层——一把&quot;锋利 V + 经验修补&quot;的剑,剑本身只是 <code>ItemStack</code>,真正的差异全在贴上去的附魔组件里。</p></blockquote><hr><h2 id="六、运行时信号-不存盘-只在-tick-间流动" tabindex="-1">六、运行时信号:不存盘,只在 tick 间流动 <a class="header-anchor" href="#六、运行时信号-不存盘-只在-tick-间流动" aria-label="Permalink to &quot;六、运行时信号:不存盘,只在 tick 间流动&quot;">​</a></h2><p>前面讲的多偏&quot;状态 / 数据&quot;。但还有一类东西<strong>从不进存档</strong>,它们是<strong>瞬时的事件 / 信号</strong>,只在第四篇讲的 tick 循环里产生、传播、消失。</p><table tabindex="0"><thead><tr><th>信号</th><th>怎么传</th><th>谁响应</th></tr></thead><tbody><tr><td>红石信号</td><td>邻居更新级联(第四篇)</td><td>红石元件、活塞、漏斗…</td></tr><tr><td>游戏事件 / 振动 GameEvent</td><td>在世界里广播,按频率分类</td><td>幽匿感测体、监守者(1.17 幽匿系统)</td></tr><tr><td>声音 SoundEvent</td><td>触发即播放,客户端侧</td><td>玩家(基本不留存)</td></tr><tr><td>scheduled / random tick</td><td>时间维度的&quot;延迟信号&quot;(第四篇)</td><td>流体扩散、作物生长…</td></tr></tbody></table><p>它们的共同特征:</p><blockquote><p><strong>没有&quot;存在哪&quot;的问题,只有&quot;何时发生、传到哪&quot;。</strong> 你存档里找不到&quot;一条红石信号&quot;&quot;一次振动&quot;,存档里只有产生它们的方块布局。</p></blockquote><p>幽匿那套尤其典型:你放方块、走路、开箱,都会<strong>广播一个游戏事件</strong>,感测体监听并按事件频率响应。这是纯运行时广播,关掉游戏什么都不剩。</p><hr><h2 id="七、交互-会话层-玩家与世界之间的临时桥" tabindex="-1">七、交互 / 会话层:玩家与世界之间的临时桥 <a class="header-anchor" href="#七、交互-会话层-玩家与世界之间的临时桥" aria-label="Permalink to &quot;七、交互 / 会话层:玩家与世界之间的临时桥&quot;">​</a></h2><p>还有一类对象,既不在世界格子里、也不贴在实体上,而是<strong>临时存在于&quot;玩家&quot;和&quot;世界&quot;之间</strong>。</p><ul><li><strong>菜单 Menu / 容器(ScreenHandler)</strong>:你打开箱子时,服务端<strong>临时创建一个 Menu</strong>,把箱子的槽位<strong>同步给客户端</strong>;你拖动物品其实是在和这个 Menu 通信;关掉界面它就销毁。第九篇讲大箱子时那个把两个单箱子拼成 54 格视图的 <code>CompoundContainer</code>,就是塞进这个 Menu 的。</li><li><strong>网络连接 / 玩家会话</strong>:每个在线玩家对应一条连接和一份同步状态。</li></ul><blockquote><p>它们都是<strong>临时、不进存档</strong>的——是&quot;交互过程&quot;的载体,不是&quot;世界内容&quot;。这也解释了为什么开着箱子界面时世界还在背后照常 tick:界面是会话层的临时对象,世界是另一套。</p></blockquote><hr><h2 id="八、最外层-维度与存档容器" tabindex="-1">八、最外层:维度与存档容器 <a class="header-anchor" href="#八、最外层-维度与存档容器" aria-label="Permalink to &quot;八、最外层:维度与存档容器&quot;">​</a></h2><p>最后,把镜头拉到最远——所有上述东西都装在哪?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>存档 World(level.dat:种子 / 出生点 / 时间 / 游戏规则 / DataVersion)</span></span>
<span class="line"><span>├── 维度 Overworld   (DIM,主世界:独立 chunk 存储)</span></span>
<span class="line"><span>├── 维度 Nether      (DIM-1,下界:独立 chunk、独立环境规则)</span></span>
<span class="line"><span>├── 维度 End         (DIM1,末地)</span></span>
<span class="line"><span>├── 维度 自定义…     (数据包定义,动态注册表)</span></span>
<span class="line"><span>└── 数据包 Datapack:配方 / 战利品表 / 进度 / 标签 / 动态注册表(JSON)</span></span></code></pre></div><ul><li><strong>维度 Level / Dimension</strong>:主世界、下界、末地,以及自定义维度。每个是一个<strong>独立的世界</strong>——独立的 chunk 存储、独立的时间、独立的高度与环境规则(由<strong>维度类型 DimensionType</strong> 定义,而 DimensionType 本身就是动态注册表里的条目)。</li><li><strong>存档 World</strong>:<code>level.dat</code>(GZip 的 NBT)那一层,管种子、出生点、游戏规则、DataVersion 等<strong>全局状态</strong>。</li><li><strong>数据包 Datapack</strong>:配方、战利品表、进度、谓词、函数、标签、动态注册表全是 JSON 定义的<strong>游戏内容规则</strong>。它描述&quot;游戏怎么玩&quot;,可被替换——这正是 Minecraft 高度可定制的来源,也和本篇开头的注册表首尾呼应:<strong>数据包之所以能改游戏,是因为内容定义和动态注册表对它开放。</strong></li></ul><hr><h2 id="九、串联-从-对象-到-系统-再到一张总图" tabindex="-1">九、串联:从&quot;对象&quot;到&quot;系统&quot;,再到一张总图 <a class="header-anchor" href="#九、串联-从-对象-到-系统-再到一张总图" aria-label="Permalink to &quot;九、串联:从&quot;对象&quot;到&quot;系统&quot;,再到一张总图&quot;">​</a></h2><p>到这里,我们其实跨过了一条边界:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前十篇:世界里的&quot;逐实例对象&quot;      —— 有限集,基本已穷举</span></span>
<span class="line"><span>  方块 · 流体 · 方块实体 · 实体 · 物品 · 生物群系 · 光照 · (粒子)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本篇:  引擎里的&quot;系统 / 层&quot;        —— 开放集,可以一直拆</span></span>
<span class="line"><span>  注册表(元系统) · 修饰层 · 运行时信号 · 交互会话 · 维度 / 存档 / 数据包</span></span></code></pre></div><p>这条边界很重要:当你问&quot;Minecraft 里还有什么&quot;,其实在问两个不同的问题——</p><ul><li><strong>&quot;世界里有哪些对象?&quot;</strong> 是有限的,前十篇那张表基本到头。</li><li><strong>&quot;引擎里有哪些系统?&quot;</strong> 是开放的,因为那不再是&quot;世界里有什么&quot;,而是&quot;游戏怎么运转&quot;,可以一直往下拆(还有碰撞形状、AI 的 Brain/记忆、结构生成、命令 / 函数 / 谓词……)。</li></ul><p>而<strong>注册表是这两者的接缝</strong>:每个&quot;对象类型&quot;都是注册表里的条目,每个&quot;系统&quot;又都绕着注册表的 ID、同步、数据驱动来组织。</p><p>下一篇(也是最后一篇),我们把这十一篇——从体素、噪声、渲染,到 tick、区块生命、实体,到 Region、NBT、Palette,再到方块三层、其它对象、注册表——<strong>全部缝成一张分层架构总图</strong>,并用&quot;一个 16³ section 从生成 → 运行 → 存盘 → 加载&quot;的完整生命周期时序,把横向的数据流也画出来,给整个系列收口。</p>`,75)])])}const h=o(s,[["render",r]]);export{q as __pageData,h as default};
